// Preparar cenas para gera��o via Veo 2
const data = $input.first().json.scriptData || $input.first().json;
const cenas = data.cenas || data.script?.cenas || [];

const tempDir = `${process.env.TEMP_DIR || '/data/temp'}/${data.videoId}`;

const fs = require('fs');
fs.mkdirSync(tempDir, { recursive: true });

// Sufixo visual obrigat�rio em todos os prompts
const VISUAL_SUFFIX = ', divine golden light breaking through clouds, heavenly atmosphere, ancient Judea first century AD, cinematic composition, photorealistic, ultra detailed, no text overlay, no watermark, no modern elements, no anachronisms';

return cenas.map((cena, i) => ({
  json: {
    videoId: data.videoId,
    cenaNumero: cena.numero || (i + 1),
    duracaoSegundos: Math.min(Math.max(cena.duracao_segundos || 6, 5), 8),
    prompt: cena.prompt_imagem + VISUAL_SUFFIX,
    tempDir,
    outputFile: `${tempDir}/scene_${String(i + 1).padStart(2, '0')}.mp4`,
    retryCount: 0
  }
}));

// Guardar operation name + dados da cena para polling
const operationData = $input.first().json;
const sceneData = $('Prepare Scenes').first().json;

const operationName = operationData.name;
if (!operationName) {
  throw new Error('Veo 2 n�o retornou operation name. Resposta: ' + JSON.stringify(operationData));
}

return [{
  json: {
    videoId: sceneData.videoId,
    cenaNumero: sceneData.cenaNumero,
    outputFile: sceneData.outputFile,
    tempDir: sceneData.tempDir,
    operationName,
    pollCount: 0
  }
}];

const statusData = $input.first().json;
const prevData = $('Save Operation Name').first().json;

const isDone = statusData.done === true;
const pollCount = (prevData.pollCount || 0) + 1;
const maxPolls = 20; // m�ximo ~5 minutos (20 x 15s)

if (!isDone && pollCount >= maxPolls) {
  throw new Error(`Veo 2 timeout ap�s ${pollCount} tentativas para cena ${prevData.cenaNumero}`);
}

// Extrair URL do v�deo se pronto
let videoUri = null;
if (isDone) {
  const samples = statusData.response?.generateVideoResponse?.generatedSamples;
  if (samples && samples.length > 0) {
    videoUri = samples[0].video?.uri;
  }
  if (!videoUri) {
    throw new Error('Veo 2 concluiu mas sem URI de v�deo. Resposta: ' + JSON.stringify(statusData));
  }
}

return [{
  json: {
    ...prevData,
    pollCount,
    isDone,
    videoUri
  }
}];

const cmdOut = $input.first().json.stdout || '';
const match = cmdOut.match(/PROCESSED:(.+)/);
const processedFile = match ? match[1].trim() : $('Check Status').first().json.outputFile;

const sceneData = $('Check Status').first().json;

return [{
  json: {
    videoId: sceneData.videoId,
    cenaNumero: sceneData.cenaNumero,
    outputFile: processedFile,
    status: 'scene_ready'
  }
}];

// Todas as cenas prontas � montar resumo
const allScenes = $input.all();
const videoId = allScenes[0]?.json?.videoId;

return [{
  json: {
    videoId,
    totalScenes: allScenes.length,
    scenes: allScenes.map(s => ({
      numero: s.json.cenaNumero,
      file: s.json.outputFile,
      status: s.json.status
    })),
    status: 'all_scenes_ready'
  }
}];
